  import org.apache.log4j.Logger;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import java.text.SimpleDateFormat;

  Logger logger = Logger.getLogger("Ascension.Rule.IdentityAttribute.DateOfBirth.DOB");
  String result =  "";
  if(link !=null){
    String linkValue = link.getAttribute("DateOfBirth");
    linkValue = decryptAES(linkValue);
    if(Util.isNotNullOrEmpty(linkValue) && linkValue.length() == 4){
		try{
			SimpleDateFormat dobSDF = new SimpleDateFormat("MMdd");
			SimpleDateFormat dobOutSDF = new SimpleDateFormat("MM/dd");
			result = dobOutSDF.format(dobSDF.parse(linkValue));
      result = encryptAES(result);
		}catch(Exception ex){
			logger.error("Exception in MDStaff DOB Rule "+ex.getMessage());
		}
    }
  }
  
  return result;
